SELECT 900020, 'Alternating Renegade Row', mg.id, 'kettlebell', NULL, '["Place two kettlebells on the floor about shoulder width apart. Position yourself on your toes and your hands as though you were doing a pushup, with the body straight and extended. Use the handles of the kettlebells to support your upper body. You may need to position your feet wide for support.","Push one kettlebell into the floor and row the other kettlebell, retracting the shoulder blade of the working side as you flex the elbow, pulling it to your side.","Then lower the kettlebell to the floor and begin the kettlebell in the opposite hand. Repeat for several reps."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 2
ON CONFLICT ("sourceId") DO NOTHING;
