SELECT 900021, 'Bent Press', mg.id, 'kettlebell', NULL, '["Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so. This will be your starting position.","Begin my leaning to the side opposite the kettlebell, continuing until you are able to touch the ground with your free hand, keeping your eyes on the kettlebell. As you do so, press the weight vertically be extending through the elbow, keeping your arm perpendicular to the ground.","Return to an upright position, with the kettlebell above your head. Return the kettlebell to the shoulder and repeat for the desired number of repetitions."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 12
ON CONFLICT ("sourceId") DO NOTHING;
