ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900044, 'Kettlebell Turkish Get-Up (Squat style)', mg.id, 'kettlebell', NULL, '["Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.","Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position.","Using your free hand, push yourself to a seated position, then progressing to your feet. While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900045, 'Kettlebell Windmill', mg.id, 'kettlebell', NULL, '["Place a kettlebell in front of your lead foot and clean and press it overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward. Press it overhead by extending the elbow.","Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell. Bending at the hip to one side, sticking your butt out, slowly lean until you can touch the floor with your free hand. Keep your eyes on the kettlebell that you hold over your head at all times.","Pause for a second after reaching the ground and reverse the motion back to the starting position."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 12
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900046, 'Leg-Over Floor Press', mg.id, 'kettlebell', NULL, '["Lie on the floor with one kettlebell in place on your chest, holding it by the handle. Extend leg on working side over leg on non-working side.Your free arm can be extended out to your side for support.","Press the kettlebll into a locked out position.","Lower the weight until the elbow touches the ground, keeping the kettlebell above the elbow. Repeat for the desired number of repetitions."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 1
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900047, 'Lunge Pass Through', mg.id, 'kettlebell', NULL, '["Stand with your torso upright holding a kettlebell in your right hand. This will be your starting position.","Step forward with your left foot and lower your upper body down by flexing the hip and the knee, keeping the torso upright. Lower your back knee until it nearly touches the ground.","As you lunge, pass the kettlebell under your front leg to your opposite hand.","Pressing through the heel of your foot, return to the starting position.","Repeat the movement for the recommended amount of repetitions, alternating legs."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 8
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900048, 'One-Arm Kettlebell Clean', mg.id, 'kettlebell', NULL, '["Place a kettlebell between your feet. As you bend down to grab the kettlebell, push your butt back and keep your eyes looking forward.","Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.","Return the weight to the starting position."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 8
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900049, 'One-Arm Kettlebell Clean and Jerk', mg.id, 'kettlebell', NULL, '["Hold a kettlebell by the handle.","Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward.","Dip your body by bending the knees, keeping your torso upright.","Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight.","Receive the weight overhead by returning to a squat position underneath the weight.","Keeping the weight overhead, return to a standing position. Lower the weight to the floor to perform the next repetition."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900050, 'One-Arm Kettlebell Floor Press', mg.id, 'kettlebell', NULL, '["Lie on the floor holding a kettlebell with one hand, with your upper arm supported by the floor. The palm should be facing in.","Press the kettlebell straight up toward the ceiling, rotating your wrist.","Lower the kettlebell back to the starting position and repeat."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 1
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900051, 'One-Arm Kettlebell Jerk', mg.id, 'kettlebell', NULL, '["Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.","Dip your body by bending the knees, keeping your torso upright.","Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight. Receive the weight overhead by returning to a squat position underneath the weight. Keeping the weight overhead, return to a standing position.","Lower the weight to perform the next repetition."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900052, 'One-Arm Kettlebell Military Press To The Side', mg.id, 'kettlebell', NULL, '["Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces inward. This will be your starting position.","Look at the kettlebell and press it up and out until it is locked out overhead.","Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900053, 'One-Arm Kettlebell Para Press', mg.id, 'kettlebell', NULL, '["Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.","Hold the kettlebell with the elbow out to the side, and press it up and out until it is locked out overhead.","Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900054, 'One-Arm Kettlebell Push Press', mg.id, 'kettlebell', NULL, '["Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.","Dip your body by bending the knees, keeping your torso upright.","Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight. Lower the weight to perform the next repetition."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900055, 'One-Arm Kettlebell Row', mg.id, 'kettlebell', NULL, '["Place a kettlebell in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position. Grab the kettlebell and pull it to your stomach, retracting your shoulder blade and flexing the elbow. Keep your back straight. Lower and repeat."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 2
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900056, 'One-Arm Kettlebell Snatch', mg.id, 'kettlebell', NULL, '["Place a kettlebell between your feet. Bend your knees and push your butt back to get in the proper starting position.","Look straight ahead and swing the kettlebell back between your legs.","Immediately reverse the direction and drive through with your hips and knees, accelerating the kettlebell upward. As the kettlebell rises to your shoulder rotate your hand and punch straight up, using momentum to receive the weight locked out overhead."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900057, 'One-Arm Kettlebell Split Jerk', mg.id, 'kettlebell', NULL, '["Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.","Dip your body by bending the knees, keeping your torso upright.","Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight.","Receive the weight overhead by returning to a squat position underneath the weight, positioning one leg in front of you and one leg behind you.","Keeping the weight overhead, return to a standing position and bring your feet together. Lower the weight to perform the next repetition."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900058, 'One-Arm Kettlebell Split Snatch', mg.id, 'kettlebell', NULL, '["Hold a kettlebell in one hand by the handle.","Squat towards the floor, and then reverse the motion, extending the hips, knees, and finally the ankles, to raise the kettlebell overhead.","After fully extending the body, descend into a lunge position to receive the weights overhead, one leg forward and one leg back. Ensure you drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.","Return to a standing position, holding the weight overhead, and bring the feet together. Lower the weight to return to the starting position."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900059, 'One-Arm Open Palm Kettlebell Clean', mg.id, 'kettlebell', NULL, '["Place one kettlebell between your feet.","Grab the handle with one hand and raise the kettlebell rapidly, let it flip so that the ball of the kettlebell lands in the palm of your hand.","Throw the kettlebell out in front of you and catch the handle with one hand.","Take the kettlebell to the floor and repeat. Make sure to work both arms."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 8
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900060, 'One-Arm Overhead Kettlebell Squats', mg.id, 'kettlebell', NULL, '["Clean and press a kettlebell with one arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so. Press the weight overhead by extending through the elbow.This will be your starting position.","Looking straight ahead and keeping a kettlebell locked out above you, flex the knees and hips and lower your torso between your legs, keeping your head and chest up.","Pause at the bottom position for a second before rising back to the top, driving through the heels of your feet."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 6
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900061, 'Open Palm Kettlebell Clean', mg.id, 'kettlebell', NULL, '["Place one kettlebell between your feet. Clean the kettlebell by extending through the legs and hips as you raise the kettlebell towards your shoulders.","Release the kettlebell as it comes up, and let it flip so that the ball of the kettlebell lands in the palms of your hands.","Release the kettlebell out in front of you and catch the handle with both hands. Lower the kettlebell to the starting position and repeat."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 8
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900062, 'Plyo Kettlebell Pushups', mg.id, 'kettlebell', NULL, '["Place a kettlebell on the floor. Place yourself in a pushup position, on your toes with one hand on the ground and one hand holding the kettlebell, with your elbows extended. This will be your starting position.","Begin by lowering yourself as low as you can, keeping your back straight.","Quickly and forcefully reverse direction, pushing yourself up to the other side of the kettlebell, switching hands as you do so. Continue the movement by descending and repeating the movement back and forth."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 1
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900063, 'Two-Arm Kettlebell Clean', mg.id, 'kettlebell', NULL, '["Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.","Clean the kettlebells to your shoulders by extending through the legs and hips as you raise the kettlebells towards your shoulders. Rotate your wrists as you do so.","Lower the kettlebells back to the starting position and repeat."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900064, 'Two-Arm Kettlebell Jerk', mg.id, 'kettlebell', NULL, '["Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you swing the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. Squat down a few inches and reverse the motion rapidly driving both kettlebells overhead. Immediately after the initial push, squat down again and get under the kettlebells. Once the kettlebells are locked out, stand upright to complete the exercise."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900065, 'Two-Arm Kettlebell Military Press', mg.id, 'kettlebell', NULL, '["Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you swing the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward.","Press the kettlebells up and out. As the kettlebells pass your head, lean into the weights so that the kettlebells are racked behind your head. Make sure to contract your lats, butt, and stomach for added stability."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 5
ON CONFLICT ("sourceId") DO NOTHING;
INSERT INTO public."Exercise" ("sourceId", name, "muscleGroupId", "exerciseType", "youtubeId", notes, "isCustom", "userId")
SELECT 900066, 'Two-Arm Kettlebell Row', mg.id, 'kettlebell', NULL, '["Place two kettlebells in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position.","Grab both kettlebells and pull them to your stomach, retracting your shoulder blades and flexing the elbows. Keep your back straight. Lower and repeat."]', false, NULL
FROM public."MuscleGroup" mg WHERE mg."sourceId" = 2
ON CONFLICT ("sourceId") DO NOTHING;

